import { HANDBOOK_DATA, HandbookChapter, HandbookSection, HandbookEntry } from '../handbookData';

// ─── DICTIONARIES ───

import EN_DICT from './en_dict.json';
import DE_DICT from './de_dict.json';
import ES_DICT from './es_dict.json';

// ─── TRANSLATOR ENGINE ───

function translateText(text: string, dict: Record<string, string>): string {
    if (!text) return text;
    // Exact match using our full translated dictionaries (handles sentences, titles, labels, etc.)
    if (dict[text]) return dict[text];

    // Fallback original text if no translation found (covers numbers, short codes, formulas)
    return text;
}

function processEntry(entry: HandbookEntry, dict: Record<string, string>): HandbookEntry {
    return {
        ...entry,
        title: translateText(entry.title, dict),
        content: translateText(entry.content, dict),
        tags: entry.tags ? entry.tags.map(t => translateText(t, dict)) : [],
        table: entry.table ? {
            headers: entry.table.headers.map(h => translateText(h, dict)),
            rows: entry.table.rows.map(row => row.map(cell => translateText(cell, dict)))
        } : undefined
    };
}

function processSection(section: HandbookSection, dict: Record<string, string>): HandbookSection {
    return {
        ...section,
        title: translateText(section.title, dict),
        entries: section.entries.map(e => processEntry(e, dict))
    };
}

function processChapter(chapter: HandbookChapter, dict: Record<string, string>): HandbookChapter {
    return {
        ...chapter,
        title: translateText(chapter.title, dict),
        sections: chapter.sections.map(s => processSection(s, dict))
    };
}

export function getLocalizedHandbookData(lang: string): HandbookChapter[] {
    let dict: Record<string, string>;
    switch (lang) {
        case 'en': dict = EN_DICT; break;
        case 'de': dict = DE_DICT; break;
        case 'es': dict = ES_DICT; break;
        case 'tr': return HANDBOOK_DATA; // Return original
        default: return HANDBOOK_DATA;
    }

    // Deep clone and translate
    return HANDBOOK_DATA.map(chapter => processChapter(chapter, dict));
}
