'use client';

/**
 * 📖 Engineering Handbook Module
 * 
 * Interactive, searchable engineering reference with:
 * - Chapter/section tree navigation
 * - Formula display
 * - Data tables
 * - Fuzzy search across all entries
 */

import React, { useState, useMemo } from 'react';
import { Search, ChevronRight, ChevronDown, BookOpen, X } from 'lucide-react';
import { HandbookChapter, HandbookSection, HandbookEntry } from '@/data/handbookData';
import { getLocalizedHandbookData } from '@/data/locales/handbookTranslations';
import { useI18nStore } from '@/store/i18nStore';

export function EngineeringHandbookModule() {
    const { t, language } = useI18nStore();

    // Dynamic Translation Data Provider
    const LOCALIZED_DATA = useMemo(() => getLocalizedHandbookData(language), [language]);

    const [searchQuery, setSearchQuery] = useState('');
    const [activeChapterId, setActiveChapterId] = useState(LOCALIZED_DATA[0]?.id || '');
    const [activeSectionId, setActiveSectionId] = useState('');
    const [activeEntryId, setActiveEntryId] = useState('');
    const [expandedChapters, setExpandedChapters] = useState<string[]>([LOCALIZED_DATA[0]?.id || '']);

    // Search across all entries
    const searchResults = useMemo(() => {
        if (!searchQuery.trim()) return null;
        const q = searchQuery.toLowerCase();
        const results: { chapter: HandbookChapter; section: HandbookSection; entry: HandbookEntry }[] = [];

        LOCALIZED_DATA.forEach(chapter => {
            chapter.sections.forEach(section => {
                section.entries.forEach(entry => {
                    const match =
                        entry.title.toLowerCase().includes(q) ||
                        entry.content.toLowerCase().includes(q) ||
                        entry.tags.some(t => t.toLowerCase().includes(q)) ||
                        (entry.formula && entry.formula.toLowerCase().includes(q));
                    if (match) results.push({ chapter, section, entry });
                });
            });
        });
        return results;
    }, [searchQuery]);

    const toggleChapter = (id: string) => {
        setExpandedChapters(prev =>
            prev.includes(id) ? prev.filter(c => c !== id) : [...prev, id]
        );
    };

    const selectEntry = (chapterId: string, sectionId: string, entryId: string) => {
        setActiveChapterId(chapterId);
        setActiveSectionId(sectionId);
        setActiveEntryId(entryId);
        setSearchQuery('');
        if (!expandedChapters.includes(chapterId)) {
            setExpandedChapters(prev => [...prev, chapterId]);
        }
    };

    // Get current display content
    const currentChapter = LOCALIZED_DATA.find(c => c.id === activeChapterId);
    const currentSection = currentChapter?.sections.find(s => s.id === activeSectionId);
    const currentEntry = currentSection?.entries.find(e => e.id === activeEntryId);

    // If no entry selected, show section overview or chapter overview
    const displayEntries = currentSection?.entries || currentChapter?.sections.flatMap(s => s.entries) || [];

    return (
        <div className="flex h-full bg-[#060a0f] text-gray-300 font-sans overflow-hidden select-none">
            {/* ─── LEFT SIDEBAR: NAVIGATION ─── */}
            <div className="w-72 border-r border-white/5 bg-[#0a0e14] flex flex-col">
                {/* Header */}
                <div className="px-4 py-4 border-b border-white/5">
                    <div className="flex items-center gap-2 mb-3">
                        <BookOpen size={18} className="text-emerald-400" />
                        <span className="text-sm font-bold text-white tracking-wider uppercase">{t.handbookTitle}</span>
                    </div>

                    {/* Search */}
                    <div className="relative">
                        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                        <input
                            type="text"
                            value={searchQuery}
                            onChange={e => setSearchQuery(e.target.value)}
                            placeholder={t.handbookSearch}
                            className="w-full pl-9 pr-8 py-2 bg-black/50 border border-white/10 rounded-lg text-xs text-white placeholder-gray-600 outline-none focus:border-emerald-500/50"
                        />
                        {searchQuery && (
                            <button onClick={() => setSearchQuery('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-500 hover:text-white">
                                <X size={12} />
                            </button>
                        )}
                    </div>
                </div>

                {/* Search Results or Chapter Tree */}
                <div className="flex-1 overflow-y-auto custom-scrollbar">
                    {searchResults ? (
                        <div className="p-2">
                            <div className="text-[10px] text-gray-500 uppercase tracking-wider px-2 py-1 mb-1">
                                {searchResults.length} {t.handbookResults}
                            </div>
                            {searchResults.map(r => (
                                <button
                                    key={r.entry.id}
                                    onClick={() => selectEntry(r.chapter.id, r.section.id, r.entry.id)}
                                    className="w-full text-left px-3 py-2 rounded-lg text-xs hover:bg-emerald-500/10 transition-colors mb-0.5"
                                >
                                    <div className="text-white font-medium">{r.entry.title}</div>
                                    <div className="text-[10px] text-gray-500 mt-0.5">{r.chapter.title} › {r.section.title}</div>
                                </button>
                            ))}
                            {searchResults.length === 0 && (
                                <div className="text-xs text-gray-600 text-center py-8">{t.handbookNoResults}</div>
                            )}
                        </div>
                    ) : (
                        <div className="py-1">
                            {LOCALIZED_DATA.map(chapter => (
                                <div key={chapter.id}>
                                    <button
                                        onClick={() => { toggleChapter(chapter.id); setActiveChapterId(chapter.id); setActiveSectionId(''); setActiveEntryId(''); }}
                                        className={`w-full flex items-center gap-2 px-3 py-2 text-xs font-bold transition-colors ${activeChapterId === chapter.id ? 'text-emerald-400 bg-emerald-500/5' : 'text-gray-400 hover:text-white hover:bg-white/5'}`}
                                    >
                                        <span className="text-sm">{chapter.icon}</span>
                                        {expandedChapters.includes(chapter.id) ? <ChevronDown size={12} /> : <ChevronRight size={12} />}
                                        <span className="truncate">{chapter.title}</span>
                                    </button>

                                    {expandedChapters.includes(chapter.id) && (
                                        <div className="ml-4 border-l border-white/5">
                                            {chapter.sections.map(section => (
                                                <button
                                                    key={section.id}
                                                    onClick={() => { setActiveChapterId(chapter.id); setActiveSectionId(section.id); setActiveEntryId(''); }}
                                                    className={`w-full text-left px-4 py-1.5 text-[11px] transition-colors ${activeSectionId === section.id ? 'text-emerald-400 bg-emerald-500/5' : 'text-gray-500 hover:text-white hover:bg-white/5'}`}
                                                >
                                                    {section.icon} {section.title}
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* ─── MAIN CONTENT ─── */}
            <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
                {/* Breadcrumb */}
                <div className="text-[10px] text-gray-500 uppercase tracking-wider mb-4 flex items-center gap-1">
                    <span>{currentChapter?.icon}</span>
                    <span>{currentChapter?.title || 'Kitapçık'}</span>
                    {currentSection && <><ChevronRight size={10} /><span>{currentSection.title}</span></>}
                    {currentEntry && <><ChevronRight size={10} /><span className="text-emerald-400">{currentEntry.title}</span></>}
                </div>

                {/* Title */}
                <h1 className="text-2xl font-black text-white mb-6 tracking-wide">
                    {currentEntry?.title || currentSection?.title || currentChapter?.title || t.handbookTitle}
                </h1>

                {/* If single entry selected */}
                {currentEntry ? (
                    <EntryCard entry={currentEntry} />
                ) : (
                    /* Show all entries in section/chapter */
                    <div className="space-y-4">
                        {displayEntries.map(entry => (
                            <div key={entry.id} onClick={() => {
                                const ch = LOCALIZED_DATA.find(c => c.sections.some(s => s.entries.some(e => e.id === entry.id)));
                                const sec = ch?.sections.find(s => s.entries.some(e => e.id === entry.id));
                                if (ch && sec) selectEntry(ch.id, sec.id, entry.id);
                            }} className="cursor-pointer">
                                <EntryCard entry={entry} compact />
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

// ═══════════════════════════════════════════════════════════════
// ENTRY CARD
// ═══════════════════════════════════════════════════════════════

function EntryCard({ entry, compact = false }: { entry: HandbookEntry; compact?: boolean }) {
    return (
        <div className={`bg-[#0c1017] border border-white/5 rounded-xl ${compact ? 'p-4 hover:border-emerald-500/30 transition-colors' : 'p-6'}`}>
            {/* Title */}
            <h3 className={`font-bold text-white ${compact ? 'text-sm mb-2' : 'text-lg mb-3'}`}>
                {entry.title}
            </h3>

            {/* Description */}
            <p className={`text-gray-400 leading-relaxed ${compact ? 'text-xs' : 'text-sm mb-4'}`}>
                {entry.content}
            </p>

            {/* Illustration */}
            {entry.image && (
                <div className={`rounded-xl overflow-hidden border border-white/10 bg-black/30 ${compact ? 'mt-2' : 'my-4'}`}>
                    <img
                        src={entry.image}
                        alt={entry.title}
                        loading="lazy"
                        className={`w-full h-auto object-contain ${compact ? 'max-h-[220px]' : 'max-h-[500px]'}`}
                    />
                </div>
            )}

            {/* Formula */}
            {entry.formula && (
                <div className={`bg-black/50 border border-emerald-500/10 rounded-lg ${compact ? 'p-2 mt-2' : 'p-4 mt-4'}`}>
                    <div className="text-[8px] text-emerald-500 uppercase tracking-widest mb-1">Formül</div>
                    <pre className={`text-emerald-300 font-mono whitespace-pre-wrap ${compact ? 'text-[10px]' : 'text-sm'}`}>
                        {entry.formula}
                    </pre>
                </div>
            )}

            {/* Table */}
            {entry.table && (
                <div className={`overflow-x-auto ${compact ? 'mt-2' : 'mt-4'}`}>
                    <table className="w-full text-xs border-collapse">
                        <thead>
                            <tr>
                                {entry.table.headers.map((h, i) => (
                                    <th key={i} className="text-left px-3 py-2 text-[10px] font-bold text-gray-500 uppercase tracking-wider border-b border-white/10 bg-black/30">
                                        {h}
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {entry.table.rows.map((row, i) => (
                                <tr key={i} className="border-b border-white/5 hover:bg-white/[0.02] transition-colors">
                                    {row.map((cell, j) => (
                                        <td key={j} className={`px-3 py-1.5 ${j === 0 ? 'text-white font-medium' : 'text-gray-400 font-mono'}`}>
                                            {cell}
                                        </td>
                                    ))}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Tags */}
            {!compact && entry.tags.length > 0 && (
                <div className="flex flex-wrap gap-1.5 mt-4">
                    {entry.tags.map(tag => (
                        <span key={tag} className="px-2 py-0.5 text-[9px] bg-emerald-500/10 text-emerald-400 rounded-full border border-emerald-500/20">
                            {tag}
                        </span>
                    ))}
                </div>
            )}
        </div>
    );
}

export default EngineeringHandbookModule;
